    multiset.sort((a, b) => a - b);
    const used = new Array(multiset.length).fill(false);
    const result: number[][] = [];
    const path: number[] = [];
    const backtrack = () => {
        if (path.length === multiset.length) {
            result.push([...path]);
            return;
        }
        for (let i = 0; i < multiset.length; i++) {
            if (used[i]) continue;
            if (i > 0 && multiset[i] === multiset[i - 1] && !used[i - 1]) continue;
            used[i] = true;
            path.push(multiset[i]);
            backtrack();
            path.pop();
            used[i] = false;
        }
    };
    backtrack();
    return result;
