                    let remaining_arr: number[] = [];
                    for (let d = 1; d <= 9; d++) {
                        const cnt = counts[d - 1];
                        for (let j = 0; j < cnt; j++) {
                            remaining_arr.push(d);
                        }
                    }
                    remaining_arr.sort((a, b) => a - b);
                    const smallest_remaining = remaining_arr.join('');
                    const full_left = current + smallest_remaining;
                    const entire_str = full_left + center_char + reverse(full_left);
                    const num_val = BigInt(entire_str);
                    if (num_val < candidate_local) {
                        candidate_local = num_val;
                    }
                    return;
                }

                const min_char = parseInt(str_n[i]);
                for (let d = 1; d <= 9; d++) {
                    if (counts[d - 1] <= 0) continue;
                    if (d < min_char) continue;

                    let new_counts = [...counts];
                    new_counts[d - 1]--;
                    let new_current = current + String(d);

                    if (d > min_char) {
                        let remaining_arr: number[] = [];
                        for (let d_in = 1; d_in <= 9; d_in++) {
                            const cnt = new_counts[d_in - 1];
                            for (let j = 0; j < cnt; j++) {
                                remaining_arr.push(d_in);
                            }
                        }
                        remaining_arr.sort((a, b) => a - b);
                        const smallest_remaining = remaining_arr.join('');
                        const full_left = new_current + smallest_remaining;
                        const entire_str = full_left + center_char + reverse(full_left);
                        const num_val = BigInt(entire_str);
                        if (num_val < candidate_local) {
                            candidate_local = num_val;
                        }
                        break;
                    } else {
                        dfs(i + 1, new_counts, new_current);
                    }
                }
            };

            dfs(0, counts, '');
            candidate_set = candidate_local;
        }

        if (candidate_set < global_candidate) {
            global_candidate = candidate_set;
        }
    }

    const candidateNumber = Number(global_candidate);
    if (candidateNumber <= Number.MAX_SAFE_INTEGER) {
        return candidateNumber;
    } else {
        throw new Error("The found candidate is not safely representable as a JavaScript number");
    }
}
